SELECT [DDT_Picking Header].No_, [Sales Line].[customer order ref_], [Sales Line].[Document No_] AS OrderNo, [NavisionEan-step0].[Cross-Reference No_] AS EAN, [NavisionEan-step0-UPC].[Cross-Reference No_] AS UPC, Val([ddt_picking line.quantity]) AS qty, [DDT_Picking Line].[season code], [DDT_Picking Header].[Sell-to Customer No_], IIf([status]=0,"Aperto",IIf([status]=1,"Rilasciato",IIf([status]=20,"Registrato","???"))) AS status_, [DDT_Picking Header].[Posted Date], Item.[Model Item No_], Item.[Variable Code 01] AS Color, Item.[Variable Code 02] AS Taglia, (Val([Sales Line.Line Amount])-Val([Sales Line.Inv_ Discount Amount]))*[qty]/Val([sales line].[quantity]) AS NetValue, Item.[Tariff No_], Item.[Country_Region of Origin Code], Val([Item.Gross Weight])*[qty] AS GrossWeightTotal, Val([Item.Net Weight])*[qty] AS NetWeightTotal, Val([Item.Unit Volume])*[qty] AS VolumeTotal
FROM (((([DDT_Picking Header] INNER JOIN [DDT_Picking Line] ON ([DDT_Picking Line].[Document No_] = [DDT_Picking Header].No_) AND ([DDT_Picking Header].[Document Type] = [DDT_Picking Line].[Document Type])) INNER JOIN Item ON [DDT_Picking Line].No_ = Item.No_) INNER JOIN [Sales Line] ON ([DDT_Picking Line].[Order Line No_] = [Sales Line].[Line No_]) AND ([DDT_Picking Line].[Order No_] = [Sales Line].[Document No_])) LEFT JOIN [NavisionEan-step0] ON [DDT_Picking Line].No_ = [NavisionEan-step0].[Item No_]) LEFT JOIN [NavisionEan-step0-UPC] ON [DDT_Picking Line].No_ = [NavisionEan-step0-UPC].[Item No_]
WHERE ((([DDT_Picking Line].[season code])=[FORMS]![PRINCIPALE]![FiltroStagioneEAN2]) AND (([DDT_Picking Header].[Sell-to Customer No_])=[FORMS]![PRINCIPALE]![FILTROCLIENTEEAN]) AND (([DDT_Picking Header].[Document Type])=0) AND ((Item.[advertising material])=0) AND (([DDT_Picking Line].Type)=2));

